  const [promotionFrom, setPromotionFrom] = useState('');
  const [promotionTo, setPromotionTo] = useState('');
  const [promotionSession, setPromotionSession] = useState('');
  const [promotionDecisions, setPromotionDecisions] = useState<Record<string, 'promote' | 'detain'>>({});

  const handlePromoteStudents = async (fromClass: string, toClass: string, nextSession: string) => {
    if (!fromClass || !toClass || !nextSession) {
      alert('Please select current class, next class, and next session');
      return;
    }
    const studentsInClass = students.filter((s: any) => s.class === fromClass);
    if (studentsInClass.length === 0) {
      alert(`No students found in ${fromClass}`);
      return;
    }

    if (!confirm(`Are you sure you want to promote/detain ${studentsInClass.length} students?`)) return;

    const updated = students.map((s: any) => {
      if (s.class === fromClass) {
        const decision = promotionDecisions[s.id] || 'promote';
        if (decision === 'promote') {
          return { ...s, class: toClass, session: nextSession };
        }
      }
      return s;
    });

    if (supabase) {
      try {
        const updates = studentsInClass.map((s: any) => {
          const decision = promotionDecisions[s.id] || 'promote';
          if (decision === 'promote') {
            return { id: s.id, class_name: toClass, academic_session: nextSession };
          }
          return null;
        }).filter(Boolean);

        if (updates.length > 0) {
          const { error } = await supabase.from('students').upsert(updates);
          if (error) throw error;
        }

        setStudents(updated);
        const promotedCount = updates.length;
        const detainedCount = studentsInClass.length - promotedCount;
        alert(`Promotion completed & saved! ${promotedCount} promoted, ${detainedCount} detained.`);
      } catch (err) {
        console.error('Error promoting students:', err);
        alert('Failed to save promotion to database');
      }
    } else {
      setStudents(updated);
      const promotedCount = studentsInClass.filter(s => (promotionDecisions[s.id] || 'promote') === 'promote').length;
      const detainedCount = studentsInClass.length - promotedCount;
      alert(`Promotion completed locally! ${promotedCount} promoted, ${detainedCount} detained.`);
    }
    
    setPromotionFrom('');
    setPromotionTo('');
    setPromotionSession('');
    setPromotionDecisions({});
  };

  const [rollClass, setRollClass] = useState('');
  const [rollSection, setRollSection] = useState('');
  const [rollSearch, setRollSearch] = useState('');
  const [rollNumberChanges, setRollNumberChanges] = useState<Record<string, string>>({});

  const handleSaveRollNumbers = async (updatedStudents: any[]) => {
    if (!supabase) {
      showModal('Error', 'Database connection not available. Please check your configuration.');
      return;
    }

    try {
      // Use individual updates instead of upsert to avoid triggering NOT NULL constraints on other columns
      const updatePromises = updatedStudents.map(s => 
        supabase
          .from('students')
          .update({ roll_number: s.rollNumber })
          .eq('id', s.id)
      );

      const results = await Promise.all(updatePromises);
      const firstError = results.find(r => r.error)?.error;

      if (firstError) {
        console.error('Error saving roll numbers:', firstError);
        showModal('Error', `Failed to save roll numbers: ${firstError.message}`);
        return;
      }

      // Update local state
      const newStudents = students.map((s: any) => {
        const updated = updatedStudents.find(us => us.id === s.id);
        return updated ? { ...s, rollNumber: updated.rollNumber } : s;
      });
      setStudents(newStudents);
      showModal('Success', 'Roll numbers saved successfully to database!');
    } catch (err: any) {
      console.error('Unexpected error:', err);
      showModal('Error', `An unexpected error occurred: ${err.message}`);
    }
  };

