  const getStudentDueFees = (student: any, session?: string) => {
    if (!student) return 0;
    const targetSession = session || student.session || '2024-25';
    
    // Check if student is in hostel
    const isHosteller = hostelBeds.some(bed => bed.studentId === student.studentId && bed.status === 'Occupied');
    
    const classFees = feeMaster.filter((f: any) => 
      f.class === student.class && 
      f.session === targetSession &&
      (f.studentType === 'Both' || !f.studentType || f.studentType === student.studentType) &&
      (f.feeType !== 'Hostel Fee' || isHosteller) // Only include hostel fee if hosteller
    );
    if (classFees.length === 0) return 0;
    
    const settledAmount = feeTransactions
      .filter((t: any) => t.studentId === student.studentId && t.session === targetSession)
      .reduce((sum: number, t: any) => sum + t.totalPaid + (t.discount || 0) + (t.scholarship || 0) - (t.fine || 0), 0);
      
    const today = new Date();
    const sessionStartYear = parseInt(targetSession.split('-')[0]);
    const sessionStartDate = new Date(sessionStartYear, 3, 1); // April 1st
    
    const admissionDate = student.admissionDate ? new Date(student.admissionDate) : sessionStartDate;
    const referenceDate = student.studentType === 'New' ? admissionDate : sessionStartDate;

    // Sum all fees for the class based on current date
    const totalDue = classFees.reduce((sum: number, f: any) => {
      let multiplier = 0;
      
      if (f.frequency === 'Yearly') {
        if (today >= new Date(referenceDate.getFullYear(), referenceDate.getMonth(), 1)) {
          multiplier = 1;
        }
      } else if (f.frequency === 'Monthly') {
        const monthsDiff = (today.getFullYear() - referenceDate.getFullYear()) * 12 + (today.getMonth() - referenceDate.getMonth()) + 1;
        multiplier = Math.min(12, Math.max(0, monthsDiff));
      } else if (f.frequency === 'Quarterly') {
        const monthsDiff = (today.getFullYear() - referenceDate.getFullYear()) * 12 + (today.getMonth() - referenceDate.getMonth()) + 1;
        multiplier = Math.min(4, Math.max(0, Math.ceil(monthsDiff / 3)));
      } else if (f.frequency === 'Half-Yearly') {
        const monthsDiff = (today.getFullYear() - referenceDate.getFullYear()) * 12 + (today.getMonth() - referenceDate.getMonth()) + 1;
        multiplier = Math.min(2, Math.max(0, Math.ceil(monthsDiff / 6)));
      } else {
        multiplier = 1;
      }
      
      return sum + (f.amount * multiplier);
    }, 0);
    
    return Math.max(0, totalDue - settledAmount);
  };
