  const [bulkMode, setBulkMode] = useState(false);

  const handlePrint = () => {
    window.print();
  };

  const handleDownloadPDF = async (person: any) => {
    // If marksheet is active, we look for marksheet element
    const elementId = (activeTab === 'marksheet' || activeTab === 'report') 
      ? `marksheet-${person.studentId || person.id}` 
      : `card-${person.id || person.studentId}`;
      
    const element = document.getElementById(elementId);
    if (!element) {
      console.warn('Element not found for download:', elementId);
      return;
    }
    
    try {
      const canvas = await html2canvas(element, {
        scale: 2,
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff'
      });
      const imgData = canvas.toDataURL('image/png');
      
      const isMarkSheet = activeTab === 'marksheet';
      const pdf = new jsPDF({
        orientation: isMarkSheet || orientation === 'landscape' ? 'landscape' : 'portrait',
        unit: 'px',
        format: [canvas.width, canvas.height]
      });
      
      pdf.addImage(imgData, 'PNG', 0, 0, canvas.width, canvas.height);
      const fileName = `${activeTab}-${person.name}-${person.studentId || person.id}.pdf`;
      pdf.save(fileName);
    } catch (error) {
      console.error('Error generating PDF:', error);
      alert('Error generating PDF. Please try printing instead.');
    }
  };

  const handleBulkDownload = async () => {
    alert('Bulk download started. This may take a moment...');
    for (const p of filteredPeople) {
      await handleDownloadPDF(p);
      // Small delay to prevent browser from blocking multiple downloads
      await new Promise(resolve => setTimeout(resolve, 500));
    }
  };

